  // wants_intense_care === true  : prefer 'intensiv' (2), 'alle' neutral (1), 'leicht' gegenteilig (0)
  // wants_intense_care === false : prefer 'leicht'   (2), 'alle' neutral (1), 'intensiv' gegenteilig (0)
  const prodIntens = String(prod.intensitaet || 'alle').trim().toLowerCase() || 'alle';
