// ── Helpers ──
function getProfileValue(flag) {
  if (flag in f) return f[flag];
  if (flag in p) return p[flag];
  if (flag in n) return n[flag];
  if (flag in pl) return pl[flag];
  return undefined;
}

function triggerMatches(flag, expected) {
  if (!flag || expected === undefined || expected === null || expected === '') return true;
  const actual = getProfileValue(flag);
  if (actual === undefined || actual === null) return false;

  const allowed = String(expected).split('|').map(s => s.trim());
  const norm = v => {
    if (v === true || v === 'TRUE' || v === 'true') return 'TRUE';
    if (v === false || v === 'FALSE' || v === 'false') return 'FALSE';
    return String(v);
  };
  const actualNorm = norm(actual);

  if (Array.isArray(actual)) {
    return allowed.some(a => actual.map(norm).includes(norm(a)));
  }
  return allowed.map(norm).includes(actualNorm);
}

function productMatches(prod, matchTyp, matchWert) {
  if (!matchTyp || !matchWert) return false;
  const werte = String(matchWert).split(',').map(s => s.trim());
  switch (matchTyp) {
    case 'produkt_key':  return werte.includes(prod.produkt_key);
    case 'produktlinie': return werte.includes(prod.produktlinie);
    case 'key_contains': return werte.some(w => prod.produkt_key?.includes(w));
    default: return false;
  }
}

// Bestimmt ob ein Produkt nach action entfernt werden soll.
// Slot-Priorität schützt ggf.
function shouldRemove(prod, action) {
  const slotPrio = slotPrioMap[prod.slot_typ] || 'optional';
  switch (action) {
    case 'exclude_product':
      return true;
    case 'exclude_unless_required':
      return slotPrio !== 'required_always';
    case 'suppress_optional':
      return slotPrio === 'optional';
    default:
      return false;
  }
}

// ── Pool filtern ──
let filteredPool = [...pool];
const appliedRules = [];

for (const rule of rules) {
  if (String(rule.aktiv).toUpperCase() !== 'TRUE') continue;

  const t1 = triggerMatches(rule.trigger_flag, rule.trigger_wert);
  const t2 = triggerMatches(rule.trigger_flag2, rule.trigger_wert2);
  if (!t1 || !t2) continue;

  const before = filteredPool.length;
  const removed = [];

  filteredPool = filteredPool.filter(prod => {
    if (productMatches(prod, rule.match_typ, rule.match_wert)) {
      if (shouldRemove(prod, rule.action)) {
        removed.push(prod.produkt_key);
        return false;
      }
    }
    return true;
  });

  if (before - filteredPool.length > 0) {
    appliedRules.push({
      konflikt_id: rule.konflikt_id,
      beschreibung: rule.beschreibung,
      removed_products: removed,
      removed_count: removed.length
    });
  }
}

