let raiseMatched = null;
for (const rule of raiseRules) {
  if (evalOverrideRule(rule, n)) {
    raiseMatched = rule.regel_id;
    const target = LEVEL_TO_NUM[String(rule.ziel_level).toUpperCase()];
    if (target) {
      // Override wirkt auf beide Levels (Backward-Compat + Zustand-Match)
      let mutatedGesamt = false;
      let mutatedZustand = false;
      if (levelNum < target) {
        levelNum = target;
        level = NUM_TO_LEVEL[target];
        mutatedGesamt = true;
      }
      if (zustandLevelNum < target) {
        zustandLevelNum = target;
        zustandLevel = NUM_TO_LEVEL[target];
        mutatedZustand = true;
      }
      if (mutatedGesamt || mutatedZustand) {
